package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        // Create CSVFormat.DEFAULT and use reflection to set escapeCharacter to null
        CSVFormat format = CSVFormat.DEFAULT;
        java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("escapeCharacter");
        field.setAccessible(true);
        field.set(format, null);

        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        // Create CSVFormat.DEFAULT and use reflection to set escapeCharacter to '\\'
        CSVFormat format = CSVFormat.DEFAULT;
        java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("escapeCharacter");
        field.setAccessible(true);
        field.set(format, '\\');

        assertTrue(format.isEscapeCharacterSet());
    }
}
